import argparse
import sys
from kafka import KafkaAdminClient
from kafka.admin import NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import KafkaError
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

def create_admin_client(bootstrap_servers, sasl_mechanism=None, username=None, password=None, security_protocol='PLAINTEXT'):
    """Create a secure Kafka AdminClient with appropriate security configuration."""
    try:
        client_config = {
            'bootstrap_servers': bootstrap_servers,
            'api_version': (2, 8, 0)
        }
        
        if security_protocol == 'SASL_SSL':
            client_config.update({
                'security_protocol': 'SASL_SSL',
                'sasl_mechanism': sasl_mechanism or 'PLAIN',
                'sasl_plain_username': username,
                'sasl_plain_password': password,
                'ssl_check_hostname': False,
                'ssl_verify': False
            })
        elif security_protocol == 'SSL':
            client_config.update({
                'security_protocol': 'SSL',
                'ssl_check_hostname': False,
                'ssl_verify': False
            })
        elif security_protocol == 'SASL_PLAINTEXT':
            client_config.update({
                'security_protocol': 'SASL_PLAINTEXT',
                'sasl_mechanism': sasl_mechanism or 'PLAIN',
                'sasl_plain_username': username,
                'sasl_plain_password': password
            })
        
        return KafkaAdminClient(**client_config)
    except Exception as e:
        logger.error(f"Failed to create AdminClient: {e}")
        sys.exit(1)

def create_topics(admin_client, topics_config):
    """Create topics with specified configurations."""
    try:
        new_topics = []
        for topic_config in topics_config:
            topic_name = topic_config['name']
            partitions = topic_config.get('partitions', 1)
            replication_factor = topic_config.get('replication_factor', 1)
            config = topic_config.get('config', {})
            
            new_topic = NewTopic(
                name=topic_name,
                num_partitions=partitions,
                replication_factor=replication_factor,
                topic_configs=config
            )
            new_topics.append(new_topic)
        
        if new_topics:
            created_topics = admin_client.create_topics(new_topics, validate_only=False)
            logger.info(f"Created topics: {list(created_topics.keys())}")
        else:
            logger.info("No topics to create")
            
    except KafkaError as e:
        logger.error(f"Failed to create topics: {e}")
        sys.exit(1)

def list_topics(admin_client):
    """List all topics in the cluster."""
    try:
        topics = admin_client.list_topics()
        logger.info(f"Topics in cluster: {topics}")
        return topics
    except KafkaError as e:
        logger.error(f"Failed to list topics: {e}")
        sys.exit(1)

def describe_topic(admin_client, topic_name):
    """Describe a specific topic's configuration."""
    try:
        config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
        configs = admin_client.describe_configs([config_resource])
        logger.info(f"Configuration for topic {topic_name}: {configs}")
        return configs
    except KafkaError as e:
        logger.error(f"Failed to describe topic {topic_name}: {e}")
        sys.exit(1)

def delete_topic(admin_client, topic_name):
    """Delete a topic."""
    try:
        admin_client.delete_topics([topic_name])
        logger.info(f"Deleted topic: {topic_name}")
    except KafkaError as e:
        logger.error(f"Failed to delete topic {topic_name}: {e}")
        sys.exit(1)

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers')
    parser.add_argument('--action', choices=['create', 'list', 'describe', 'delete'], required=True, help='Action to perform')
    parser.add_argument('--topic', help='Topic name for describe or delete actions')
    parser.add_argument('--topics', nargs='*', help='Topic configurations in format "name:partitions:replication_factor:key1=value1:key2=value2"')
    parser.add_argument('--security-protocol', choices=['PLAINTEXT', 'SSL', 'SASL_PLAINTEXT', 'SASL_SSL'], default='PLAINTEXT', help='Security protocol')
    parser.add_argument('--sasl-mechanism', choices=['PLAIN', 'SCRAM-SHA-256', 'SCRAM-SHA-512'], help='SASL mechanism')
    parser.add_argument('--username', help='Username for SASL authentication')
    parser.add_argument('--password', help='Password for SASL authentication')
    
    args = parser.parse_args()
    
    # Create secure AdminClient
    admin_client = create_admin_client(
        bootstrap_servers=args.bootstrap_servers,
        sasl_mechanism=args.sasl_mechanism,
        username=args.username,
        password=args.password,
        security_protocol=args.security_protocol
    )
    
    if args.action == 'create':
        topics_config = []
        if args.topics:
            for topic_str in args.topics:
                parts = topic_str.split(':')
                topic_name = parts[0]
                partitions = int(parts[1]) if len(parts) > 1 else 1
                replication_factor = int(parts[2]) if len(parts) > 2 else 1
                
                config = {}
                for i in range(3, len(parts)):
                    if '=' in parts[i]:
                        key, value = parts[i].split('=', 1)
                        config[key] = value
                
                topics_config.append({
                    'name': topic_name,
                    'partitions': partitions,
                    'replication_factor': replication_factor,
                    'config': config
                })
        
        create_topics(admin_client, topics_config)
        
    elif args.action == 'list':
        list_topics(admin_client)
        
    elif args.action == 'describe':
        if not args.topic:
            logger.error("Topic name required for describe action")
            sys.exit(1)
        describe_topic(admin_client, args.topic)
        
    elif args.action == 'delete':
        if not args.topic:
            logger.error("Topic name required for delete action")
            sys.exit(1)
        delete_topic(admin_client, args.topic)

if __name__ == '__main__':
    main()